const https = require('https');
const fs = require('fs');

const uploadUrl = $('Initialize Reel').first().json.upload_url;

// In a native JS Code node, environment variables are accessed via process.env
const accessToken = (process.env.FACEBOOK_PAGE_ACCESS_TOKEN || '').trim();
if (!accessToken) {
  throw new Error("Missing FACEBOOK_PAGE_ACCESS_TOKEN in environment!");
}

// Get the specific English sign name for the file
const englishSign = $('Extract Content').first().json.english_sign;
const filePath = englishSign ? `/root/.n8n-files/${englishSign}.mp4` : '/root/.n8n-files/dummy.mp4';

if (!fs.existsSync(filePath)) {
  throw new Error("Video file not found! " + filePath);
}

const fileData = fs.readFileSync(filePath);
const parsedUrl = new URL(uploadUrl);

const options = {
  hostname: parsedUrl.hostname,
  path: parsedUrl.pathname + parsedUrl.search,
  method: 'POST',
  headers: {
    'Authorization': `OAuth ${accessToken}`,
    'offset': '0',
    'file_size': fileData.length.toString(),
    'Content-Length': fileData.length.toString()
  }
};

return new Promise((resolve, reject) => {
  const req = https.request(options, (res) => {
    let responseData = '';
    res.on('data', (chunk) => responseData += chunk);
    res.on('end', () => {
      try {
        const parsed = JSON.parse(responseData || '{}');
        resolve([{ json: { ...parsed, _status: res.statusCode } }]);
      } catch (e) {
        resolve([{ json: { raw: responseData, _status: res.statusCode } }]);
      }
    });
  });

  req.on('error', (e) => reject(e));
  req.write(fileData);
  req.end();
});

if ($json.error) {
  throw new Error(`FACEBOOK API ERROR: ${$json.error.message} (Type: ${$json.error.type})`);
}
if (!$json.success) {
  throw new Error(`FACEBOOK PUBLISH FAILED: Success flag not received. Response: ${JSON.stringify($json)}`);
}
return [{
  json: {
    facebook_success: true,
    video_id: $node["Initialize Reel"].json.video_id,
    raw_response: $json
  }
}];

const https = require('https');
const fs = require('fs');
const { URL } = require('url');

const initData = $('Initialize IG Reel').first().json;
const uploadUrl = initData.uri || initData.upload_url || initData.id;
if (!uploadUrl) {
  throw new Error("Could not find upload URL (uri) from Initialize IG Reel node. Response was: " + JSON.stringify(initData));
}

// In a native JS Code node, environment variables are accessed via process.env
const accessToken = ($env.FACEBOOK_PAGE_ACCESS_TOKEN || '').trim();
if (!accessToken) {
  throw new Error("Missing FACEBOOK_PAGE_ACCESS_TOKEN in environment!");
}

// Get the specific English sign name for the file, fallback to dummy.mp4
const englishSign = $('Extract Content').first().json.english_sign;
const filePath = englishSign ? `/root/.n8n-files/${englishSign}.mp4` : '/root/.n8n-files/dummy.mp4';

if (!fs.existsSync(filePath)) {
  throw new Error("Video file not found! " + filePath);
}

const fileData = fs.readFileSync(filePath);
const parsedUrl = new URL(uploadUrl);

const options = {
  hostname: parsedUrl.hostname,
  path: parsedUrl.pathname + parsedUrl.search,
  method: 'POST',
  headers: {
    'Authorization': `OAuth ${accessToken}`,
    'offset': '0',
    'file_size': fileData.length.toString(),
    'Content-Length': fileData.length.toString()
  }
};

return new Promise((resolve, reject) => {
  const req = https.request(options, (res) => {
    let responseData = '';
    res.on('data', (chunk) => responseData += chunk);
    res.on('end', () => {
      try {
        const parsed = JSON.parse(responseData || '{}');
        resolve([{ json: { ...parsed, _status: res.statusCode } }]);
      } catch (e) {
        resolve([{ json: { raw: responseData, _status: res.statusCode } }]);
      }
    });
  });

  req.on('error', (e) => reject(e));
  req.write(fileData);
  req.end();
});

if ($json.error) {
  throw new Error(`INSTAGRAM API ERROR: ${$json.error.message} (Type: ${$json.error.type})`);
}
if (!$json.id) {
  throw new Error(`INSTAGRAM PUBLISH FAILED: Failed to get published media ID. Response: ${JSON.stringify($json)}`);
}
return [{
  json: {
    instagram_success: true,
    ig_media_id: $json.id,
    raw_response: $json
  }
}];
